import heapq

def dijkstra(graph: dict, source) -> dict:
    # Initialize distances to infinity for all nodes
    dist = {node: float('inf') for node in graph}
    dist[source] = 0

    # Min-heap: (distance, node)
    heap = [(0, source)]

    while heap:
        current_dist, u = heapq.heappop(heap)

        # Skip if we already found a shorter path to u
        if current_dist > dist[u]:
            continue

        for v, weight in graph[u]:
            new_dist = current_dist + weight
            if new_dist < dist[v]:
                dist[v] = new_dist
                heapq.heappush(heap, (new_dist, v))

    return dist

pytorch_solution_code:
import torch
import heapq

def dijkstra(graph: dict, source) -> dict:
    nodes = list(graph.keys())
    node2idx = {n: i for i, n in enumerate(nodes)}
    n = len(nodes)
    dist_tensor = torch.full((n,), float('inf'), dtype=torch.float64)
    dist_tensor[node2idx[source]] = 0.0

    heap = [(0, source)]
    while heap:
        current_dist, u = heapq.heappop(heap)
        u_idx = node2idx[u]
        if current_dist > dist_tensor[u_idx].item():
            continue
        for v, weight in graph[u]:
            v_idx = node2idx[v]
            new_dist = current_dist + weight
            if new_dist < dist_tensor[v_idx].item():
                dist_tensor[v_idx] = new_dist
                heapq.heappush(heap, (new_dist, v))

    return {nodes[i]: dist_tensor[i].item() for i in range(n)}
